import { Component } from '@angular/core';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})
export class AppComponent {
  title = 'censor';
  words: string[] = [];
  newWord: string = '';
  text: string = '';

  add() { this.words.push(this.newWord); this.newWord = ''; console.log(this.words); }
  reset() { this.newWord = ''; }
}
